import { createHighlighterCore } from "shiki/core";
import { createJavaScriptRegexEngine } from "shiki/engine/javascript";

const highlightCodeCache = new Map<string, string>();
const jsEngine = createJavaScriptRegexEngine();
const highlighterPromise = createHighlighterCore({
	themes: [import("@shikijs/themes/github-dark"), import("@shikijs/themes/github-light-default")],
	langs: [import("@shikijs/langs/typescript"), import("@shikijs/langs/svelte")],
	engine: jsEngine,
});

export async function highlightCode(code: string, language: string = "svelte"): Promise<string> {
	const cachedCode = highlightCodeCache.get(code);
	if (cachedCode) return cachedCode;

	const highlighter = await highlighterPromise;

	const html = highlighter.codeToHtml(formatCode(code), {
		lang: language,
		themes: {
			dark: "github-dark",
			light: "github-light-default",
		},
		transformers: [
			{
				pre(node) {
					node.properties["class"] =
						"no-scrollbar min-w-0 overflow-x-auto px-4 py-3.5 outline-none has-[[data-highlighted-line]]:px-0 has-[[data-line-numbers]]:px-0 has-[[data-slot=tabs]]:p-0 !bg-transparent";
				},
				code(node) {
					node.properties["data-line-numbers"] = "";
				},
				line(node) {
					node.properties["data-line"] = "";
				},
			},
		],
	});

	highlightCodeCache.set(code, html);

	return html;
}

function formatCode(code: string): string {
	return code.replace(/\t/g, "  ");
}

import type {UrlObject} from "url";

import Image from "next/image";
import Link from "next/link";

import {cn} from "@/utils/cn";

interface DocsImageProps {
  src: string;
  darkSrc?: string;
  alt: string;
  className?: string;
  width?: number;
  wrapperClassName?: string;
  height?: number;
  priority?: boolean;
  href?: string;
}

export function DocsImage({
  alt,
  className,
  darkSrc,
  height = 1000,
  href,
  priority = true,
  src,
  width = 1000,
  wrapperClassName,
}: DocsImageProps) {
  const wrapperClasses = cn(
    "not-prose relative block aspect-18/9 w-full overflow-hidden rounded-xl border border-separator",
    wrapperClassName,
  );

  const imageContent = darkSrc ? (
    <>
      <Image
        alt={alt}
        className={cn("absolute inset-0 block h-full w-full object-cover dark:hidden", className)}
        height={height}
        priority={priority}
        src={src}
        width={width}
      />
      <Image
        alt={alt}
        className={cn("absolute inset-0 hidden h-full w-full object-cover dark:block", className)}
        height={height}
        priority={priority}
        src={darkSrc}
        width={width}
      />
    </>
  ) : (
    <Image
      alt={alt}
      className={cn("absolute inset-0 h-full w-full object-contain", className)}
      height={height}
      priority={priority}
      src={src}
      width={width}
    />
  );

  if (href) {
    return (
      <Link className={wrapperClasses} href={href as unknown as UrlObject}>
        {imageContent}
      </Link>
    );
  }

  return <div className={wrapperClasses}>{imageContent}</div>;
}
